sql:
SELECT AVG(heart_rate) AS average_heart_rate
FROM vital_signs
WHERE patient_id = 1;

SELECT patient_id, MAX(measurement_time) AS latest_measurement_time
FROM vital_signs
GROUP BY patient_id;

SELECT SUM(quantity) AS total_quantity
FROM antibodies
WHERE patient_id = 1 AND antibody_name = 'Anti-Body A';

SELECT patient_id
FROM patients
ORDER BY patient_id ASC;

SELECT COUNT(patient_id) AS patient_count
FROM patient_diseases
WHERE disease_id = 0;

external_knowledge:
- 'struggling to breathe' refers to a blood oxygen level below 95; 
- 'heart racing like a marathon runner' refers to a heart rate above 100; 
- 'sugar disorder' refers to Diabetes.
